+            focus_visibility: FocusVisibility::Normal,
+            show_shortcut_hints: true,
+        };
+        let palette = SemanticPalette::from_preferences(false, &prefs);
+        assert_eq!(palette.bg, SemanticPalette::high_contrast_dark().bg);
+    }
