+    #[test]
+    fn focus_indicator_from_preferences() {
+        let mut prefs = DisplayPreferences::new();
+        assert_eq!(
+            FocusIndicatorSpec::from_preferences(&prefs),
+            FocusIndicatorSpec::NORMAL
+        );
+        prefs.toggle_focus_visibility();
+        assert_eq!(
+            FocusIndicatorSpec::from_preferences(&prefs),
+            FocusIndicatorSpec::ENHANCED
+        );
