+        const { assert!(FocusIndicatorSpec::ENHANCED.bold_border) };
+        const { assert!(!FocusIndicatorSpec::NORMAL.left_bar) };
+        const { assert!(!FocusIndicatorSpec::NORMAL.bold_border) };
